dashboard.definition:
{
  "dataSources": {
    "ds_score": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=summary | head 1 | eval value=overall_score | table value",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_status": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=summary | head 1 | eval value=overall_status | table value",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_critical": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=summary | head 1 | eval value=critical_count | table value",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_warning": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=summary | head 1 | eval value=warning_count | table value",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_info": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=summary | head 1 | eval value=info_count | table value",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_ok": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=summary | head 1 | eval value=ok_count | table value",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_domains": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=domain_score | dedup domain | table domain_label domain_score | sort -domain_score | rename domain_label as Domain, domain_score as Score",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_score_trend": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=summary | dedup audit_id sortby _time | timechart span=1d latest(overall_score) as Score | fields - _span _spandays",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_all_findings": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=finding | dedup check | eval icon=case(severity=\"CRITICAL\",\"▸ CRIT\", severity=\"WARNING\",\"▸ WARN\", severity=\"INFO\",\"▸ INFO\", severity=\"OK\",\"▸ PASS\", 1=1, severity) | table icon domain_label check_label result severity score | sort severity score | rename icon as \" \", domain_label as Domain, check_label as Check, result as Result, severity as Severity, score as Score",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_critical_findings": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=finding severity=CRITICAL | dedup check | table domain_label check_label result detail score | rename domain_label as Domain, check_label as Check, result as Result, detail as Detail, score as Score",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_warning_findings": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=finding severity=WARNING | dedup check | table domain_label check_label result detail score | rename domain_label as Domain, check_label as Check, result as Result, detail as Detail, score as Score",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_info_findings": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=finding severity=INFO | dedup check | table domain_label check_label result detail score | rename domain_label as Domain, check_label as Check, result as Result, detail as Detail, score as Score",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_ok_findings": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=finding severity=OK | dedup check | table domain_label check_label result score | rename domain_label as Domain, check_label as Check, result as Result, score as Score",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_last_audit": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=summary | head 1 | eval value=audit_time.\"  ·  score \".overall_score.\"/100  ·  \".overall_status | table value",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_fix_prompt": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=finding severity!=OK | dedup check | where isnotnull(fix_prompt) AND fix_prompt!=\"\" | eval line=\"[\" . severity . \"] \" . check_label . \": \" . result . \" — FIX: \" . fix_prompt | stats values(line) as lines | eval prompt=\"I just ran a SPLUNK-BOT audit on my Splunk Enterprise instance. Here are the findings that need attention:\\n\\n\" . mvjoin(lines, \"\\n\\n\") . \"\\n\\nPlease help me fix these issues. For each finding, provide the specific commands or config changes needed. My SPLUNK_HOME is /opt/splunk and I am user dave with SSH access.\" | table prompt",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_splunk_ver": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=summary | head 1 | eval value=splunk_version | table value",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    },
    "ds_host": {
      "type": "ds.search",
      "options": {
        "query": "| savedsearch \"SPLUNK-BOT Dashboard Cache\" | search event_type=summary | head 1 | eval value=host | table value",
        "queryParameters": {"earliest":"-90d","latest":"now"},
        "refresh": "5m",
        "refreshType": "delay"
      }
    }
  },
  "defaults": {},
  "inputs": {},
  "visualizations": {
    "viz_title": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# ▸ SPLUNK-BOT",
        "fontColor": "#00ff41"
      }
    },
    "viz_subtitle": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "_Platform health audit  ·  8 domains  ·  weighted scoring  ·  severity analysis_",
        "fontColor": "#00994d"
      }
    },
    "viz_run_btn": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "#### [▸ RUN AUDIT](/app/splunk_bot/search?q=%7C%20runaudit&earliest=-1m&latest=now)",
        "fontColor": "#00ff41"
      }
    },

    "card_hero": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#091209","fillOpacity":0.92,"strokeColor":"#00ff41","strokeWidth":1.5,"rx":6}
    },
    "viz_score": {
      "type": "splunk.singlevalue",
      "title": "HEALTH SCORE",
      "dataSources": {"primary": "ds_score"},
      "options": {"majorFontSize":72,"majorColor":"#00ff41","backgroundColor":"transparent","sparklineDisplay":"off","trendDisplay":"off","unit":"/ 100","unitPosition":"after"},
      "containerOptions": {"title": {"color": "#00994d"}}
    },
    "viz_status": {
      "type": "splunk.singlevalue",
      "title": "STATUS",
      "dataSources": {"primary": "ds_status"},
      "options": {"majorFontSize":48,"majorColor":"#00ff41","backgroundColor":"transparent","sparklineDisplay":"off","trendDisplay":"off"},
      "containerOptions": {"title": {"color": "#00994d"}}
    },
    "sep_hero": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#00ff41","fillOpacity":0.12,"strokeColor":"transparent","rx":0}
    },
    "viz_host": {
      "type": "splunk.singlevalue",
      "title": "HOST",
      "dataSources": {"primary": "ds_host"},
      "options": {"majorFontSize":22,"majorColor":"#00cc55","backgroundColor":"transparent","sparklineDisplay":"off","trendDisplay":"off"},
      "containerOptions": {"title": {"color": "#00994d"}}
    },
    "viz_ver": {
      "type": "splunk.singlevalue",
      "title": "SPLUNK",
      "dataSources": {"primary": "ds_splunk_ver"},
      "options": {"majorFontSize":22,"majorColor":"#00cc55","backgroundColor":"transparent","sparklineDisplay":"off","trendDisplay":"off"},
      "containerOptions": {"title": {"color": "#00994d"}}
    },

    "card_crit_count": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#1a0808","fillOpacity":0.9,"strokeColor":"#ff3b30","strokeWidth":1.5,"rx":6}
    },
    "viz_critical": {
      "type": "splunk.singlevalue",
      "title": "CRITICAL",
      "dataSources": {"primary": "ds_critical"},
      "options": {"majorFontSize":44,"majorColor":"#ff3b30","backgroundColor":"transparent","sparklineDisplay":"off","trendDisplay":"off"},
      "containerOptions": {"title": {"color": "#cc2d26"}}
    },
    "card_warn_count": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#1a1508","fillOpacity":0.9,"strokeColor":"#ffcc00","strokeWidth":1.5,"rx":6}
    },
    "viz_warning": {
      "type": "splunk.singlevalue",
      "title": "WARNING",
      "dataSources": {"primary": "ds_warning"},
      "options": {"majorFontSize":44,"majorColor":"#ffcc00","backgroundColor":"transparent","sparklineDisplay":"off","trendDisplay":"off"},
      "containerOptions": {"title": {"color": "#b39200"}}
    },
    "card_info_count": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#081218","fillOpacity":0.9,"strokeColor":"#00bfff","strokeWidth":1.5,"rx":6}
    },
    "viz_info": {
      "type": "splunk.singlevalue",
      "title": "INFO",
      "dataSources": {"primary": "ds_info"},
      "options": {"majorFontSize":44,"majorColor":"#00bfff","backgroundColor":"transparent","sparklineDisplay":"off","trendDisplay":"off"},
      "containerOptions": {"title": {"color": "#0088b3"}}
    },
    "card_ok_count": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#081208","fillOpacity":0.9,"strokeColor":"#00ff41","strokeWidth":1.5,"rx":6}
    },
    "viz_ok": {
      "type": "splunk.singlevalue",
      "title": "PASS",
      "dataSources": {"primary": "ds_ok"},
      "options": {"majorFontSize":44,"majorColor":"#00ff41","backgroundColor":"transparent","sparklineDisplay":"off","trendDisplay":"off"},
      "containerOptions": {"title": {"color": "#00994d"}}
    },

    "card_domains": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#091209","fillOpacity":0.92,"strokeColor":"#1a4a1a","strokeWidth":1,"rx":6}
    },
    "viz_domains_label": {
      "type": "splunk.markdown",
      "options": {"markdown": "##### ▸ DOMAIN SCORES", "fontColor": "#00994d"}
    },
    "viz_domains": {
      "type": "splunk.column",
      "dataSources": {"primary": "ds_domains"},
      "options": {
        "backgroundColor":"transparent",
        "seriesColors":["#00ff41"],
        "xAxisTitleVisibility":"hide",
        "yAxisTitleVisibility":"hide",
        "yAxisMax":100,
        "yAxisMin":0,
        "dataValuesDisplay": "all",
        "showRoundedStyle": true
      }
    },
    "card_trend": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#091209","fillOpacity":0.92,"strokeColor":"#1a4a1a","strokeWidth":1,"rx":6}
    },
    "viz_trend_label": {
      "type": "splunk.markdown",
      "options": {"markdown": "##### ▸ SCORE TREND", "fontColor": "#00994d"}
    },
    "viz_score_trend": {
      "type": "splunk.line",
      "dataSources": {"primary": "ds_score_trend"},
      "options": {
        "backgroundColor":"transparent",
        "seriesColors":["#00ff41"],
        "yAxisTitleVisibility":"hide",
        "xAxisTitleVisibility":"hide",
        "yAxisMax":100,
        "yAxisMin":0,
        "areaOpacity": 0.08
      }
    },

    "viz_findings_header": {
      "type": "splunk.markdown",
      "options": {"markdown": "## ▸ FINDINGS", "fontColor": "#00ff41"}
    },

    "card_crit_tbl": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#0f0606","fillOpacity":0.92,"strokeColor":"#ff3b30","strokeWidth":1.5,"rx":6}
    },
    "viz_crit_lbl": {
      "type": "splunk.markdown",
      "options": {"markdown": "##### ▸ CRITICAL", "fontColor": "#ff3b30"}
    },
    "viz_critical_findings": {
      "type": "splunk.table",
      "dataSources": {"primary": "ds_critical_findings"},
      "options": {"backgroundColor":"transparent","count":10}
    },

    "card_warn_tbl": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#100e04","fillOpacity":0.92,"strokeColor":"#ffcc00","strokeWidth":1.5,"rx":6}
    },
    "viz_warn_lbl": {
      "type": "splunk.markdown",
      "options": {"markdown": "##### ▸ WARNING", "fontColor": "#ffcc00"}
    },
    "viz_warning_findings": {
      "type": "splunk.table",
      "dataSources": {"primary": "ds_warning_findings"},
      "options": {"backgroundColor":"transparent","count":10}
    },

    "card_info_tbl": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#060d10","fillOpacity":0.92,"strokeColor":"#00bfff","strokeWidth":1.5,"rx":6}
    },
    "viz_info_lbl": {
      "type": "splunk.markdown",
      "options": {"markdown": "##### ▸ INFO", "fontColor": "#00bfff"}
    },
    "viz_info_findings": {
      "type": "splunk.table",
      "dataSources": {"primary": "ds_info_findings"},
      "options": {"backgroundColor":"transparent","count":10}
    },

    "card_ok_tbl": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#060f06","fillOpacity":0.92,"strokeColor":"#1a4a1a","strokeWidth":1,"rx":6}
    },
    "viz_ok_lbl": {
      "type": "splunk.markdown",
      "options": {"markdown": "##### ▸ PASS", "fontColor": "#00994d"}
    },
    "viz_ok_findings": {
      "type": "splunk.table",
      "dataSources": {"primary": "ds_ok_findings"},
      "options": {"backgroundColor":"transparent","count":10}
    },

    "card_fix": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#100e04","fillOpacity":0.92,"strokeColor":"#ffcc00","strokeWidth":1.5,"rx":6}
    },
    "viz_fix_header": {
      "type": "splunk.markdown",
      "options": {"markdown": "##### ▸ FIX PROMPT GENERATOR\n_Copy this into Cursor or ChatGPT to get targeted remediation commands._", "fontColor": "#ffcc00"}
    },
    "viz_fix_prompt": {
      "type": "splunk.table",
      "dataSources": {"primary": "ds_fix_prompt"},
      "options": {"backgroundColor":"transparent","count":1,"wrap":true}
    },

    "card_footer": {
      "type": "splunk.rectangle",
      "options": {"fillColor":"#091209","fillOpacity":0.92,"strokeColor":"#1a4a1a","strokeWidth":1,"rx":6}
    },
    "viz_footer_run": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "#### [▸ RUN AUDIT NOW](/app/splunk_bot/search?q=%7C%20runaudit&earliest=-1m&latest=now)\n_Executes the 8-domain audit inside Splunk. Refresh this dashboard after completion._",
        "fontColor": "#00ff41"
      }
    },
    "viz_last_audit": {
      "type": "splunk.singlevalue",
      "title": "LAST AUDIT",
      "dataSources": {"primary": "ds_last_audit"},
      "options": {"majorFontSize":16,"majorColor":"#00cc55","backgroundColor":"transparent","sparklineDisplay":"off","trendDisplay":"off"},
      "containerOptions": {"title": {"color": "#00994d"}}
    }
  },
  "layout": {
    "type": "absolute",
    "options": {
      "width": 1440,
      "height": 2360,
      "display": "auto-scale",
      "backgroundColor": "#030903",
      "backgroundImage": {"sizeType":"cover","x":0,"y":0,"src":"/static/app/splunk_bot/terminal_bg.svg"}
    },
    "structure": [
      {"item":"viz_title","type":"block","position":{"x":28,"y":62,"w":500,"h":40}},
      {"item":"viz_subtitle","type":"block","position":{"x":28,"y":98,"w":700,"h":26}},
      {"item":"viz_run_btn","type":"block","position":{"x":1250,"y":70,"w":170,"h":36}},

      {"item":"card_hero","type":"block","position":{"x":24,"y":138,"w":1392,"h":175}},
      {"item":"viz_score","type":"block","position":{"x":40,"y":142,"w":340,"h":168}},
      {"item":"sep_hero","type":"block","position":{"x":390,"y":158,"w":2,"h":136}},
      {"item":"viz_status","type":"block","position":{"x":408,"y":142,"w":280,"h":168}},
      {"item":"sep_hero","type":"block","position":{"x":700,"y":158,"w":2,"h":136}},
      {"item":"viz_host","type":"block","position":{"x":718,"y":155,"w":340,"h":80}},
      {"item":"viz_ver","type":"block","position":{"x":718,"y":230,"w":340,"h":76}},
      {"item":"sep_hero","type":"block","position":{"x":1070,"y":158,"w":2,"h":136}},
      {"item":"viz_last_audit","type":"block","position":{"x":1088,"y":155,"w":310,"h":148}},

      {"item":"card_crit_count","type":"block","position":{"x":24,"y":328,"w":342,"h":130}},
      {"item":"viz_critical","type":"block","position":{"x":24,"y":328,"w":342,"h":130}},
      {"item":"card_warn_count","type":"block","position":{"x":382,"y":328,"w":342,"h":130}},
      {"item":"viz_warning","type":"block","position":{"x":382,"y":328,"w":342,"h":130}},
      {"item":"card_info_count","type":"block","position":{"x":740,"y":328,"w":342,"h":130}},
      {"item":"viz_info","type":"block","position":{"x":740,"y":328,"w":342,"h":130}},
      {"item":"card_ok_count","type":"block","position":{"x":1098,"y":328,"w":318,"h":130}},
      {"item":"viz_ok","type":"block","position":{"x":1098,"y":328,"w":318,"h":130}},

      {"item":"card_domains","type":"block","position":{"x":24,"y":474,"w":850,"h":340}},
      {"item":"viz_domains_label","type":"block","position":{"x":40,"y":478,"w":300,"h":28}},
      {"item":"viz_domains","type":"block","position":{"x":32,"y":506,"w":834,"h":302}},
      {"item":"card_trend","type":"block","position":{"x":890,"y":474,"w":526,"h":340}},
      {"item":"viz_trend_label","type":"block","position":{"x":906,"y":478,"w":300,"h":28}},
      {"item":"viz_score_trend","type":"block","position":{"x":898,"y":506,"w":510,"h":302}},

      {"item":"viz_findings_header","type":"block","position":{"x":28,"y":832,"w":400,"h":36}},

      {"item":"card_crit_tbl","type":"block","position":{"x":24,"y":878,"w":694,"h":280}},
      {"item":"viz_crit_lbl","type":"block","position":{"x":40,"y":882,"w":200,"h":28}},
      {"item":"viz_critical_findings","type":"block","position":{"x":32,"y":910,"w":678,"h":242}},

      {"item":"card_warn_tbl","type":"block","position":{"x":734,"y":878,"w":682,"h":280}},
      {"item":"viz_warn_lbl","type":"block","position":{"x":750,"y":882,"w":200,"h":28}},
      {"item":"viz_warning_findings","type":"block","position":{"x":742,"y":910,"w":666,"h":242}},

      {"item":"card_info_tbl","type":"block","position":{"x":24,"y":1174,"w":694,"h":280}},
      {"item":"viz_info_lbl","type":"block","position":{"x":40,"y":1178,"w":200,"h":28}},
      {"item":"viz_info_findings","type":"block","position":{"x":32,"y":1206,"w":678,"h":242}},

      {"item":"card_ok_tbl","type":"block","position":{"x":734,"y":1174,"w":682,"h":280}},
      {"item":"viz_ok_lbl","type":"block","position":{"x":750,"y":1178,"w":200,"h":28}},
      {"item":"viz_ok_findings","type":"block","position":{"x":742,"y":1206,"w":666,"h":242}},

      {"item":"card_fix","type":"block","position":{"x":24,"y":1470,"w":1392,"h":300}},
      {"item":"viz_fix_header","type":"block","position":{"x":40,"y":1474,"w":1360,"h":56}},
      {"item":"viz_fix_prompt","type":"block","position":{"x":32,"y":1530,"w":1376,"h":234}},

      {"item":"card_footer","type":"block","position":{"x":24,"y":1786,"w":1392,"h":110}},
      {"item":"viz_footer_run","type":"block","position":{"x":40,"y":1790,"w":800,"h":102}},
      {"item":"viz_last_audit","type":"block","position":{"x":860,"y":1800,"w":540,"h":88}}
    ]
  }
}
